@code {
    private bool _loading = true;
    private bool _showNewForm;
    private DateTime _selectedDate = DateTime.Today;
    private List<Appointment> _appointments = new();
    private List<(DateTime Start, DateTime End)> _availableSlots = new();
    private List<Patient> _patients = new();
    private Appointment _newAppointment = new();
    private int _selectedSlotIndex = -1;

    protected override async Task OnInitializedAsync()
    {
        await LoadData();
    }

    private async Task LoadData()
    {
        _loading = true;
        _appointments = await AppointmentService.GetAppointmentsForDateAsync(_selectedDate);
        _availableSlots = await AppointmentService.GetAvailableSlotsAsync(_selectedDate);
        _patients = await PatientService.GetAllPatientsAsync();
        _loading = false;
    }

    private async Task OnDateChanged(ChangeEventArgs e)
    {
        if (DateTime.TryParse(e.Value?.ToString(), out var date))
        {
            _selectedDate = date;
            await LoadData();
        }
    }

    private void ToggleNewForm()
    {
        _showNewForm = !_showNewForm;
        if (_showNewForm)
        {
            _newAppointment = new Appointment();
            _selectedSlotIndex = -1;
        }
    }

    private async Task CreateAppointment()
    {
        if (_selectedSlotIndex >= 0 && _selectedSlotIndex < _availableSlots.Count)
        {
            var slot = _availableSlots[_selectedSlotIndex];
            _newAppointment.StartTime = slot.Start;
            _newAppointment.EndTime = slot.End;
            _newAppointment.Status = AppointmentStatus.Scheduled;
            await AppointmentService.CreateAppointmentAsync(_newAppointment);
            _showNewForm = false;
            await LoadData();
        }
    }

    private async Task CancelAppointment(int id)
    {
        await AppointmentService.CancelAppointmentAsync(id);
        await LoadData();
    }

    private string GetStatusColor(AppointmentStatus status) => status switch
    {
        AppointmentStatus.Scheduled => "primary",
        AppointmentStatus.Completed => "success",
        AppointmentStatus.Cancelled => "danger",
        _ => "secondary"
    };
}

