@page "/billing/new"
@rendermode InteractiveServer
@attribute [Authorize]
@using Microsoft.AspNetCore.Authorization
@using VetClinic.Data.Models
@using VetClinic.Services
@inject BillingService BillingService
@inject PatientService PatientService
@inject NavigationManager NavigationManager

<PageTitle>New Invoice</PageTitle>

<h1>New Invoice</h1>

@if (_loading)
{
    <p>Loading...</p>
}
else
{
    <EditForm Model="@_invoice" OnValidSubmit="HandleSubmit" FormName="invoiceForm">
        <DataAnnotationsValidator />
        <ValidationSummary />

        <div class="row mb-3">
            <div class="col-md-6">
                <label class="form-label">Patient</label>
                <InputSelect class="form-select" @bind-Value="_invoice.PatientId">
                    <option value="0">-- Select Patient --</option>
                    @foreach (var patient in _patients)
                    {
                        <option value="@patient.Id">@patient.Name (@patient.OwnerName)</option>
                    }
                </InputSelect>
            </div>
            <div class="col-md-6">
                <label class="form-label">Description</label>
                <InputText class="form-control" @bind-Value="_invoice.Description" />
            </div>
        </div>

        <h4>Line Items</h4>
        <table class="table">
            <thead>
                <tr>
                    <th>Description</th>
                    <th>Quantity</th>
                    <th>Unit Price</th>
                    <th>Total</th>
                    <th></th>
                </tr>
            </thead>
            <tbody>
                @for (int i = 0; i < _lineItems.Count; i++)
                {
                    var index = i;
                    <tr>
                        <td>
                            <input type="text" class="form-control" @bind="_lineItems[index].Description" />
                        </td>
                        <td>
                            <input type="number" class="form-control" @bind="_lineItems[index].Quantity" min="1" @bind:event="oninput" @oninput="RecalculateTotal" />
                        </td>
                        <td>
                            <input type="number" class="form-control" step="0.01" @bind="_lineItems[index].UnitPrice" @bind:event="oninput" @oninput="RecalculateTotal" />
                        </td>
                        <td>@((_lineItems[index].Quantity * _lineItems[index].UnitPrice).ToString("C"))</td>
                        <td>
                            <button type="button" class="btn btn-sm btn-outline-danger" @onclick="() => RemoveLineItem(index)">Remove</button>
                        </td>
                    </tr>
                }
            </tbody>
        </table>

        <button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddLineItem">Add Line Item</button>

        <div class="mb-3">
            <h5>Total: @_total.ToString("C")</h5>
        </div>

        <button type="submit" class="btn btn-primary">Create Invoice</button>
        <a href="/billing" class="btn btn-secondary ms-2">Cancel</a>
    </EditForm>
}

@code {
    private bool _loading = true;
    private Invoice _invoice = new();
    private List<InvoiceLineItem> _lineItems = new();
    private List<Patient> _patients = new();
    private decimal _total;

    protected override async Task OnInitializedAsync()
    {
        _patients = await PatientService.GetAllPatientsAsync();
        _lineItems.Add(new InvoiceLineItem { Quantity = 1 });
        _loading = false;
    }

    private void AddLineItem()
    {
        _lineItems.Add(new InvoiceLineItem { Quantity = 1 });
    }

    private void RemoveLineItem(int index)
    {
        if (_lineItems.Count > 1)
        {
            _lineItems.RemoveAt(index);
            RecalculateTotal();
        }
    }

    private void RecalculateTotal()
    {
        _total = _lineItems.Sum(li => li.Quantity * li.UnitPrice);
    }

    private async Task HandleSubmit()
    {
        RecalculateTotal();
        _invoice.Amount = _total;
        _invoice.IssuedDate = DateTime.Now;
        _invoice.Status = PaymentStatus.Pending;
        _invoice.LineItems = _lineItems;

        foreach (var item in _lineItems)
        {
            item.Total = item.Quantity * item.UnitPrice;
        }

        await BillingService.CreateInvoiceAsync(_invoice);
        NavigationManager.NavigateTo($"/billing/{_invoice.Id}");
    }
}

