@code {
    [Parameter] public int Id { get; set; }

    private bool _loading = true;
    private Patient? _patient;
    private List<Appointment> _appointments = new();
    private MedicalRecord _newRecord = new() { Date = DateTime.Today };

    protected override async Task OnInitializedAsync()
    {
        _patient = await PatientService.GetPatientByIdAsync(Id);
        if (_patient != null)
        {
            _appointments = await AppointmentService.GetAppointmentsByPatientAsync(Id);
        }
        _loading = false;
    }

    private async Task AddRecord()
    {
        _newRecord.PatientId = Id;
