@page "/appointments"
@rendermode InteractiveServer
@attribute [Authorize]
@using Microsoft.AspNetCore.Authorization
@using VetClinic.Data.Models
@using VetClinic.Services
@inject AppointmentService AppointmentService
@inject PatientService PatientService

<PageTitle>Appointments</PageTitle>

<h1>Appointments</h1>

<div class="row mb-3">
    <div class="col-md-4">
        <label class="form-label">Select Date</label>
        <input type="date" class="form-control" value="@_selectedDate.ToString("yyyy-MM-dd")" @onchange="OnDateChanged" />
    </div>
    <div class="col-md-8 text-end align-self-end">
        <button class="btn btn-primary" @onclick="ToggleNewForm">@(_showNewForm ? "Cancel" : "New Appointment")</button>
    </div>
</div>

@if (_showNewForm)
{
    <div class="card mb-4">
        <div class="card-body">
            <h5 class="card-title">New Appointment</h5>
            <EditForm Model="@_newAppointment" OnValidSubmit="CreateAppointment" FormName="newAppointmentForm">
                <DataAnnotationsValidator />
                <ValidationSummary />

                <div class="row">
                    <div class="col-md-3 mb-2">
                        <label class="form-label">Patient</label>
                        <InputSelect class="form-select" @bind-Value="_newAppointment.PatientId">
                            <option value="0">-- Select Patient --</option>
                            @foreach (var patient in _patients)
                            {
                                <option value="@patient.Id">@patient.Name (@patient.Species)</option>
                            }
                        </InputSelect>
                    </div>
                    <div class="col-md-3 mb-2">
                        <label class="form-label">Time Slot</label>
                        <InputSelect class="form-select" @bind-Value="_selectedSlotIndex">
                            <option value="-1">-- Select Slot --</option>
                            @for (int i = 0; i < _availableSlots.Count; i++)
                            {
                                var slot = _availableSlots[i];
                                <option value="@i">@slot.Start.ToString("HH:mm") - @slot.End.ToString("HH:mm")</option>
                            }
                        </InputSelect>
                    </div>
                    <div class="col-md-3 mb-2">
                        <label class="form-label">Reason</label>
                        <InputText class="form-control" @bind-Value="_newAppointment.Reason" />
                    </div>
