                        <label class="form-label">Veterinarian</label>
                        <InputText class="form-control" @bind-Value="_newAppointment.Veterinarian" />
                    </div>
                </div>
                <button type="submit" class="btn btn-success">Create</button>
            </EditForm>
        </div>
    </div>
}

@if (_loading)
{
    <p>Loading...</p>
}
else
{
    <h3>Schedule for @_selectedDate.ToString("dddd, MMMM d, yyyy")</h3>

    @if (_appointments.Any())
    {
        <div class="list-group">
            @foreach (var apt in _appointments.OrderBy(a => a.StartTime))
            {
                <div class="list-group-item">
                    <div class="d-flex justify-content-between align-items-start">
                        <div>
                            <h6 class="mb-1">@apt.StartTime.ToString("HH:mm") - @apt.EndTime.ToString("HH:mm")</h6>
                            <p class="mb-1"><strong>@apt.Patient?.Name</strong> — @apt.Reason</p>
                            <small class="text-muted">Vet: @apt.Veterinarian</small>
                        </div>
                        <div>
                            <span class="badge bg-@GetStatusColor(apt.Status) me-2">@apt.Status</span>
                            @if (apt.Status == AppointmentStatus.Scheduled)
                            {
                                <button class="btn btn-sm btn-outline-danger" @onclick="() => CancelAppointment(apt.Id)">Cancel</button>
                            }
                        </div>
                    </div>
                </div>
            }
        </div>
    }
    else
    {
        <p class="text-muted">No appointments for this day.</p>
    }

    @if (_availableSlots.Any())
    {
        <h5 class="mt-4">Available Slots</h5>
        <div class="d-flex flex-wrap gap-2">
            @foreach (var slot in _availableSlots)
            {
                <span class="badge bg-success p-2">@slot.Start.ToString("HH:mm") - @slot.End.ToString("HH:mm")</span>
            }
        </div>
    }
}

@code {
    private bool _loading = true;
    private bool _showNewForm;
    private DateTime _selectedDate = DateTime.Today;
    private List<Appointment> _appointments = new();
    private List<(DateTime Start, DateTime End)> _availableSlots = new();
    private List<Patient> _patients = new();
    private Appointment _newAppointment = new();
    private int _selectedSlotIndex = -1;

    protected override async Task OnInitializedAsync()
    {
        await LoadData();
    }

    private async Task LoadData()
    {
        _loading = true;
        _appointments = await AppointmentService.GetAppointmentsForDateAsync(_selectedDate);
        _availableSlots = await AppointmentService.GetAvailableSlotsAsync(_selectedDate);
        _patients = await PatientService.GetAllPatientsAsync();
        _loading = false;
    }

    private async Task OnDateChanged(ChangeEventArgs e)
    {
        if (DateTime.TryParse(e.Value?.ToString(), out var date))
        {
            _selectedDate = date;
            await LoadData();
        }
    }

    private void ToggleNewForm()
    {
        _showNewForm = !_showNewForm;
        if (_showNewForm)
        {
            _newAppointment = new Appointment();
            _selectedSlotIndex = -1;
        }
    }

    private async Task CreateAppointment()
    {
        if (_selectedSlotIndex >= 0 && _selectedSlotIndex < _availableSlots.Count)
        {
            var slot = _availableSlots[_selectedSlotIndex];
            _newAppointment.StartTime = slot.Start;
            _newAppointment.EndTime = slot.End;
            _newAppointment.Status = AppointmentStatus.Scheduled;
            await AppointmentService.CreateAppointmentAsync(_newAppointment);
            _showNewForm = false;
            await LoadData();
        }
    }

    private async Task CancelAppointment(int id)
    {
        await AppointmentService.CancelAppointmentAsync(id);
        await LoadData();
    }

    private string GetStatusColor(AppointmentStatus status) => status switch
    {
        AppointmentStatus.Scheduled => "primary",
        AppointmentStatus.Completed => "success",
        AppointmentStatus.Cancelled => "danger",
        _ => "secondary"
    };
}

