                <dt class="col-sm-3">Description</dt>
                <dd class="col-sm-9">@_invoice.Description</dd>
                <dt class="col-sm-3">Issued Date</dt>
                <dd class="col-sm-9">@_invoice.IssuedDate.ToShortDateString()</dd>
                <dt class="col-sm-3">Paid Date</dt>
                <dd class="col-sm-9">@(_invoice.PaidDate?.ToShortDateString() ?? "—")</dd>
                <dt class="col-sm-3">Total Amount</dt>
                <dd class="col-sm-9"><strong>@_invoice.Amount.ToString("C")</strong></dd>
            </dl>
        </div>
