                @foreach (var item in _invoice.LineItems)
                {
                    <tr>
                        <td>@item.Description</td>
                        <td>@item.Quantity</td>
                        <td>@item.UnitPrice.ToString("C")</td>
                        <td>@item.Total.ToString("C")</td>
                    </tr>
                }
            </tbody>
            <tfoot>
                <tr>
                    <td colspan="3" class="text-end"><strong>Total</strong></td>
                    <td><strong>@_invoice.Amount.ToString("C")</strong></td>
                </tr>
            </tfoot>
        </table>
    }
    else
    {
        <p class="text-muted">No line items.</p>
    }

    @if (_invoice.Status == PaymentStatus.Pending)
    {
        <div class="mt-3">
            <button class="btn btn-success" @onclick="MarkAsPaid">Mark as Paid</button>
            <button class="btn btn-danger ms-2" @onclick="CancelInvoice">Cancel Invoice</button>
        </div>
    }

    <a href="/billing" class="btn btn-secondary mt-3">Back to Invoices</a>
}

@code {
    [Parameter] public int Id { get; set; }

    private bool _loading = true;
    private Invoice? _invoice;

    protected override async Task OnInitializedAsync()
    {
        _invoice = await BillingService.GetInvoiceByIdAsync(Id);
        _loading = false;
    }

    private async Task MarkAsPaid()
    {
        await BillingService.ProcessPaymentAsync(Id);
        _invoice = await BillingService.GetInvoiceByIdAsync(Id);
    }

    private async Task CancelInvoice()
    {
        await BillingService.CancelInvoiceAsync(Id);
        _invoice = await BillingService.GetInvoiceByIdAsync(Id);
    }

    private string GetStatusColor(PaymentStatus status) => status switch
    {
        PaymentStatus.Pending => "warning",
        PaymentStatus.Paid => "success",
        PaymentStatus.Cancelled => "danger",
        _ => "secondary"
    };
}

