+
+    protected override async Task OnInitializedAsync()
+    {
+        await LoadData();
+    }
+
+    private async Task LoadData()
+    {
+        _loading = true;
+        _appointments = await AppointmentService.GetAppointmentsForDateAsync(_selectedDate);
+        _availableSlots = await AppointmentService.GetAvailableSlotsAsync(_selectedDate);
+        _patients = await PatientService.GetAllPatientsAsync();
+        _loading = false;
+    }
+
+    private async Task OnDateChanged(ChangeEventArgs e)
+    {
+        if (DateTime.TryParse(e.Value?.ToString(), out var date))
+        {
+            _selectedDate = date;
+            await LoadData();
+        }
+    }
+
+    private void ToggleNewForm()
+    {
+        _showNewForm = !_showNewForm;
