+        {
+            _newAppointment = new Appointment();
+            _selectedSlotIndex = -1;
+        }
+    }
+
+    private async Task CreateAppointment()
+    {
+        if (_selectedSlotIndex >= 0 && _selectedSlotIndex < _availableSlots.Count)
+        {
